  constructor(client: AxiosInstance, basePath: string) {
    this.client = client;
    this.basePath = basePath;
  }

  /**
   * Build full URL for resource endpoints
   */
  protected buildUrl(path: string = ''): string {
    return path.length > 0 
      ? `${this.basePath}/${path}` 
      : this.basePath;
  }

  /**
   * Handle HTTP errors and convert to SDK error types
   */
  protected handleError(error: unknown): never {
    // Check if it's an axios error
    if (typeof error === 'object' && error !== null && 'response' in error) {
      const axiosError = error as { 
        response?: { 
          status: number; 
          data?: Record<string, unknown>;
          headers?: Record<string, string>;
        };
        message?: string;
        code?: string;
      };

      const status = axiosError.response?.status;
      const data = axiosError.response?.data;
      const headers = axiosError.response?.headers;
      const message = data?.error?.message || axiosError.message || 'Unknown error';

      // Convert to appropriate error type
      switch (status) {
        case 400:
          throw new ApiRequestError(`Bad request: ${message}`, 400, data);
        case 401:
          throw new ApiRequestError(`Unauthorized: ${message}`, 401, data);
        case 403:
          throw new ApiRequestError(`Forbidden: ${message}`, 403, data);
        case 404:
          throw new NotFoundError(message, undefined, undefined);
        case 409:
          throw new ConflictError(message);
        case 422:
          throw new ValidationError(
            message,
            (data?.error?.details as Record<string, string[]>) || {},
            data
          );
        case 429:
          throw new RateLimitError(message, headers);
        case 500:
          throw new ApiRequestError(`Server error: ${message}`, 500, data);
        case 502:
          throw new ApiRequestError(`Bad gateway: ${message}`, 502, data);
        case 503:
          throw new ApiRequestError(`Service unavailable: ${message}`, 503, data);
        default:
          throw new ApiRequestError(
            message,
            status || 0,
            data
          );
      }
    }

    // Handle network/timeout errors
    if (typeof error === 'object' && error !== null) {
      const err = error as { code?: string; message?: string };

      if (err.code === 'ECONNABORTED' || err.code === 'ETIMEDOUT') {
        throw new TimeoutError(err.message || 'Request timed out');
      }

      if (err.code === 'ENOTFOUND' || err.code === 'ECONNREFUSED') {
        throw new NetworkError('Network connection failed', 
          error instanceof Error ? error : undefined
        );
      }
    }

    // Default: wrap in generic API error
    throw new ApiRequestError(
      error instanceof Error ? error.message : 'Unknown error',
      0
    );
  }

