/**
 * Abstract base class for API resources
 * Provides common CRUD operations and request handling
 */

import type { AxiosInstance, AxiosResponse } from 'axios';
import { 
  ApiRequestError, 
  ValidationError, 
  NotFoundError,
  ConflictError,
  RateLimitError,
  NetworkError,
  TimeoutError
} from '../errors';
import type { ApiResponse, PaginationParams, RequestOptions } from '../types';

/**
 * Abstract base resource class
 * All resource classes extend this for consistent API interaction
 */
export abstract class BaseResource {
  protected readonly client: AxiosInstance;
  protected readonly basePath: string;

  constructor(client: AxiosInstance, basePath: string) {
    this.client = client;
    this.basePath = basePath;
  }

  /**
   * Build full URL for resource endpoints
   */
  protected buildUrl(path: string = ''): string {
    return path.length > 0 
      ? `${this.basePath}/${path}` 
      : this.basePath;
  }

  /**
   * Handle HTTP errors and convert to SDK error types
   */
  protected handleError(error: unknown): never {
    // Check if it's an axios error
    if (typeof error === 'object' && error !== null && 'response' in error) {
      const axiosError = error as { 
        response?: { 
          status: number; 
          data?: Record<string, unknown>;
          headers?: Record<string, string>;
        };
        message?: string;
        code?: string;
      };

      const status = axiosError.response?.status;
      const data = axiosError.response?.data;
      const headers = axiosError.response?.headers;
      const message = data?.error?.message || axiosError.message || 'Unknown error';

      // Convert to appropriate error type
      switch (status) {
        case 400:
          throw new ApiRequestError(`Bad request: ${message}`, 400, data);
        case 401:
          throw new ApiRequestError(`Unauthorized: ${message}`, 401, data);
        case 403:
          throw new ApiRequestError(`Forbidden: ${message}`, 403, data);
        case 404:
          throw new NotFoundError(message, undefined, undefined);
        case 409:
          throw new ConflictError(message);
        case 422:
          throw new ValidationError(
            message,
            (data?.error?.details as Record<string, string[]>) || {},
            data
          );
        case 429:
          throw new RateLimitError(message, headers);
        case 500:
          throw new ApiRequestError(`Server error: ${message}`, 500, data);
        case 502:
          throw new ApiRequestError(`Bad gateway: ${message}`, 502, data);
        case 503:
          throw new ApiRequestError(`Service unavailable: ${message}`, 503, data);
        default:
          throw new ApiRequestError(
            message,
            status || 0,
            data
          );
      }
    }

    // Handle network/timeout errors
    if (typeof error === 'object' && error !== null) {
      const err = error as { code?: string; message?: string };

      if (err.code === 'ECONNABORTED' || err.code === 'ETIMEDOUT') {
        throw new TimeoutError(err.message || 'Request timed out');
      }

      if (err.code === 'ENOTFOUND' || err.code === 'ECONNREFUSED') {
        throw new NetworkError('Network connection failed', 
          error instanceof Error ? error : undefined
        );
      }
    }

    // Default: wrap in generic API error
    throw new ApiRequestError(
      error instanceof Error ? error.message : 'Unknown error',
      0
    );
  }

  /**
   * Make GET request
   */
  protected async get<T>(path: string = '', options?: RequestOptions): Promise<T> {
    try {
      const response: AxiosResponse<T> = await this.client.get(
        this.buildUrl(path),
        {
          params: options?.params,
          headers: options?.headers,
          timeout: options?.timeout,
        }
      );
      return response.data;
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Make POST request
   */
  protected async post<T>(
    path: string = '',
    data: Record<string, unknown>,
    options?: RequestOptions
  ): Promise<T> {
    try {
      const response: AxiosResponse<T> = await this.client.post(
        this.buildUrl(path),
        data,
        {
          params: options?.params,
          headers: options?.headers,
          timeout: options?.timeout,
        }
      );
      return response.data;
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Make PUT request
   */
  protected async put<T>(
    path: string,
    data: Record<string, unknown>,
    options?: RequestOptions
  ): Promise<T> {
    try {
      const response: AxiosResponse<T> = await this.client.put(
        this.buildUrl(path),
        data,
        {
          params: options?.params,
          headers: options?.headers,
          timeout: options?.timeout,
        }
      );
      return response.data;
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Make PATCH request
   */
  protected async patch<T>(
    path: string,
    data: Record<string, unknown>,
    options?: RequestOptions
  ): Promise<T> {
    try {
      const response: AxiosResponse<T> = await this.client.patch(
        this.buildUrl(path),
        data,
        {
          params: options?.params,
          headers: options?.headers,
          timeout: options?.timeout,
        }
      );
      return response.data;
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Make DELETE request
   */
  protected async delete<T>(path: string, options?: RequestOptions): Promise<T> {
    try {
      const response: AxiosResponse<T> = await this.client.delete(
        this.buildUrl(path),
        {
          params: options?.params,
          headers: options?.headers,
          timeout: options?.timeout,
        }
      );
      return response.data;
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Build pagination parameters for list requests
   */
  protected buildPaginationParams(
    params: PaginationParams = {}
  ): Record<string, string> {
    const query: Record<string, string> = {};

    if (params.page !== undefined) {
      query.page = String(params.page);
    }
    if (params.per_page !== undefined) {
      query.per_page = String(params.per_page);
    }
    if (params.sort_by) {
      query.sort_by = params.sort_by;
      if (params.sort_order) {
        query.sort_order = params.sort_order;
      }
    }

    return query;
  }
}

