// ============================================================================
// Token Management
// ============================================================================

/**
 * Token manager class for handling JWT tokens
 * Manages token storage, expiration checking, and refresh
 */
class TokenManager {
  private accessToken: string | null = null;
  private refreshToken: string | null = null;
  private expiresAt: number = 0;
  private refreshPromise: Promise<string> | null = null;

  /**
   * Set tokens from successful authentication
   */
  setTokens(auth: AuthToken): void {
    this.accessToken = auth.access_token;
    this.refreshToken = auth.refresh_token;
    this.expiresAt = auth.expires_at || Date.now() + (auth.expires_in * 1000);
    this.refreshPromise = null;
  }

  /**
   * Clear all tokens (logout)
   */
  clear(): void {
    this.accessToken = null;
    this.refreshToken = null;
    this.expiresAt = 0;
    this.refreshPromise = null;
  }

  /**
   * Check if access token is expired or about to expire
   */
  isExpired(bufferSeconds: number = 60): boolean {
    if (!this.expiresAt) return true;
    return Date.now() >= (this.expiresAt - bufferSeconds * 1000);
  }

  /**
   * Get current access token
   */
  getAccessToken(): string | null {
    return this.accessToken;
  }

  /**
   * Get refresh token
   */
  getRefreshToken(): string | null {
    return this.refreshToken;
  }

  /**
   * Check if authenticated
   */
  isAuthenticated(): boolean {
    return !!this.accessToken && !this.isExpired();
  }

  /**
   * Get or create refresh promise (prevents duplicate refresh calls)
   */
  async acquireRefreshLock(refreshFn: () => Promise<AuthToken>): Promise<string> {
    if (this.refreshPromise) {
      return this.refreshPromise;
    }

    this.refreshPromise = refreshFn().then(
      (auth) => {
        this.setTokens(auth);
        return auth.access_token;
      },
      (error) => {
        this.refreshPromise = null;
        throw error;
      }
    );

    return this.refreshPromise;
  }

  /**
   * Clear refresh promise (call after refresh completes)
   */
  clearRefreshLock(): void {
    this.refreshPromise = null;
  }
}

// ============================================================================
// Retry Logic
// ============================================================================

/**
 * Calculate delay for retry with exponential backoff
 */
function calculateRetryDelay(attempt: number, baseDelay: number): number {
  // Exponential backoff: delay = baseDelay * 2^attempt + random jitter
  const exponentialDelay = baseDelay * Math.pow(2, attempt);
  const jitter = Math.random() * 100;
  return Math.min(exponentialDelay + jitter, 30000); // Max 30 seconds
}

/**
 * Determine if request should be retried
 */
function shouldRetry(error: AxiosError): boolean {
  // Don't retry client errors (4xx) except 429 (rate limit) and 408 (timeout)
  if (error.response) {
    const status = error.response.status;
    return status === 429 || status === 408 || (status >= 500 && status < 600);
  }

  // Retry network errors
  return !!error.code && ['ECONNABORTED', 'ECONNREFUSED', 'ENOTFOUND', 'ETIMEDOUT'].includes(error.code);
}

